}


CREATE OR REPLACE FUNCTION update_blog_search_vector()
RETURNS TRIGGER AS $$
BEGIN
  NEW.search_vector :=
    setweight(to_tsvector('english', COALESCE(NEW.title, '')), 'A') ||
    setweight(to_tsvector('english', COALESCE(NEW.excerpt, '')), 'B') ||
    setweight(to_tsvector('english', COALESCE(array_to_string(NEW.tags, ' '), '')), 'C');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER blog_search_vector_update
  BEFORE INSERT OR UPDATE ON blog_posts
  FOR EACH ROW EXECUTE PROCEDURE update_blog_search_vector();

CREATE INDEX blog_search_idx ON blog_posts USING GIN(search_vector);

WITH RECURSIVE comment_tree AS ( SELECT c.*, 0 AS depth FROM forum_comments c WHERE c.thread_id = $1 AND c.parent_id IS NULL
UNION ALL
SELECT c.*, ct.depth + 1 AS depth FROM forum_comments c JOIN comment_tree ct ON c.parent_id = ct.id WHERE ct.depth < 1 ) SELECT * FROM comment_tree ORDER BY depth ASC, created_at ASC;

-- Example policies for blog_posts
-- Anyone can read published posts CREATE POLICY "read_published" ON blog_posts FOR SELECT USING (status = 'published');
-- Authors can read their own drafts CREATE POLICY "read_own_drafts" ON blog_posts FOR SELECT USING (author_id = auth.uid());
-- Authors can insert their own posts CREATE POLICY "insert_own" ON blog_posts FOR INSERT WITH CHECK (author_id = auth.uid());
-- Authors can update their own posts CREATE POLICY "update_own" ON blog_posts FOR UPDATE USING (author_id = auth.uid());
-- Admins can do anything CREATE POLICY "admin_all" ON blog_posts FOR ALL USING ( EXISTS ( SELECT 1 FROM users WHERE id = auth.uid() AND role = 'admin' ) );
